def _check_structure(element: etree._Element, result: Dict[str, Any], depth: int = 0) -> None:
    """
    Recursively checks the structure of the XML for potential issues.
    """
    MAX_DEPTH = 100
    MAX_ATTRIBUTES = 100
    MAX_CHILDREN = 10000

    if depth > MAX_DEPTH:
        result['warnings'].append(
            f"XML nesting depth exceeds {MAX_DEPTH} levels at element '{element.tag}'."
        )
        return

    # Check for excessive attributes
    if len(element.attrib) > MAX_ATTRIBUTES:
        result['warnings'].append(
            f"Element '{element.tag}' has {len(element.attrib)} attributes "
            f"(exceeds recommended maximum of {MAX_ATTRIBUTES})."
        )

    # Check for empty elements with no attributes
    if (element.text is None or element.text.strip() == '') and \
       len(element) == 0 and len(element.attrib) == 0:
        result['warnings'].append(
            f"Empty element found: '{element.tag}' (no text, children, or attributes)."
        )

    # Check for excessive children
    child_count = len(element)
    if child_count > MAX_CHILDREN:
        result['warnings'].append(
            f"Element '{element.tag}' has {child_count} children "
            f"(exceeds recommended maximum of {MAX_CHILDREN})."
        )

    # Recurse into children
    for child in element:
        _check_structure(child, result, depth + 1)


def pretty_print_results(result: Dict[str, Any]) -> str:
    """
    Formats the validation results into a human-readable string.
    """
    lines = []
    lines.append("=" * 60)
    lines.append("XML VALIDATION REPORT")
    lines.append("=" * 60)

    status = "✅ VALID" if result['valid'] else "❌ INVALID"
    lines.append(f"Status: {status}")

    if result['root_tag']:
        lines.append(f"Root Element: {result['root_tag']}")
        lines.append(f"Total Elements: {result['element_count']}")

    if result['namespaces']:
        lines.append("\nNamespaces:")
        for prefix, uri in result['namespaces'].items():
            lines.append(f"  {prefix}: {uri}")

    if result['errors']:
        lines.append(f"\nErrors ({len(result['errors'])}):")
        for i, error in enumerate(result['errors'], 1):
            lines.append(f"  {i}. {error}")

    if result['warnings']:
        lines.append(f"\nWarnings ({len(result['warnings'])}):")
        for i, warning in enumerate(result['warnings'], 1):
            lines.append(f"  {i}. {warning}")

    lines.append("=" * 60)
    return "\n".join(lines)


